export function longestCommonSubstring(s1: string, s2: string): string {
  const n = s1.length;
  const m = s2.length;
  let maxLen = 0;
  let endingIndex = 0;

  // Initialize a 2D array with zeros
  const dp = Array(n + 1)
      .fill(null)
      .map(() => Array(m + 1).fill(0));

  // Build the dp table
  for (let i = 1; i <= n; i++) {
    for (let j = 1; j <= m; j++) {
      if (s1[i - 1] === s2[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1] + 1;

        if (dp[i][j] > maxLen) {
          maxLen = dp[i][j];
          endingIndex = i;
        }
      }
    }
  }

  // Extract the longest common substring
  return s1.slice(endingIndex - maxLen, endingIndex);
}

export function mergeBy<T>(arr1: T[], arr2: T[], cb: (element: T) => string): T[] {
  const groupedArr1 = groupBy(arr1, cb)
  const groupedArr2 = groupBy(arr2, cb)
  const result: T[] = Object.values(groupedArr2).map((value) => value[value.length - 1])

  const arr2Keys = Object.keys(groupedArr2)
  Object.entries(groupedArr1).forEach(([key, value]) => {
    if (!arr2Keys.includes(key)) {
      result.push(value[value.length - 1])
    }
  })

  return result
}

const groupBy = <T>(arr: T[], cb: (element: T) => string): { [key: string]: T[] } => {
  return arr.reduce<{ [key: string]: T[] }>((acc, curr) => {
    const key = cb(curr)
    if (!acc[key]) {
      acc[key] = []
    }
    acc[key].push(curr)
    return acc
  }, {})
}

export function deepEqualObj(obj1: unknown, obj2: unknown): boolean {
  if (typeof obj1 !== typeof obj2) {
    return false
  }

  if (typeof obj1 !== "object" || obj1 === null) {
    return obj1 === obj2
  }

  if (typeof obj2 !== "object" || obj2 === null) {
    return obj2 === obj1
  }

  const obj1Keys = Object.keys(obj1)
  const obj2Keys = Object.keys(obj2)

  if (obj1Keys.length !== obj2Keys.length) {
    return false
  }

  for (const key of obj1Keys) {
    if (!obj2Keys.includes(key) || !deepEqualObj(obj1[key], obj2[key])) {
      return false
    }
  }

  return true
}

export const _safeParse: (_Err: $ZodErrorClass) => $SafeParse = (_Err) => (schema, value, _ctx) => {
  const ctx: schemas.ParseContextInternal = _ctx ? { ..._ctx, async: false } : { async: false };
  const result = schema._zod.run({ value, issues: [] }, ctx);
  if (result instanceof Promise) {
    throw new core.$ZodAsyncError();
  }

  return result.issues.length
    ? {
        success: false,
        error: new (_Err ?? errors.$ZodError)(result.issues.map((iss) => util.finalizeIssue(iss, ctx, core.config()))),
      }
    : ({ success: true, data: result.value } as any);
};

export function merge(a: schemas.$ZodObject, b: schemas.$ZodObject): any {
  if (a._zod.def.checks?.length) {
    throw new Error(".merge() cannot be used on object schemas containing refinements. Use .safeExtend() instead.");
  }
  const def = mergeDefs(a._zod.def, {
    get shape() {
      const _shape = { ...a._zod.def.shape, ...b._zod.def.shape };
      assignProp(this, "shape", _shape); // self-caching
      return _shape;
    },
    get catchall() {
      return b._zod.def.catchall;
    },
    checks: b._zod.def.checks ?? [],
  });

  return clone(a, def) as any;
}

export function finalizeIssue(
  iss: errors.$ZodRawIssue,
  ctx: schemas.ParseContextInternal | undefined,
  config: $ZodConfig
): errors.$ZodIssue {
  const message = iss.message
    ? iss.message
    : (unwrapMessage(iss.inst?._zod.def?.error?.(iss as never)) ??
      unwrapMessage(ctx?.error?.(iss as never)) ??
      unwrapMessage(config.customError?.(iss)) ??
      unwrapMessage(config.localeError?.(iss)) ??
      "Invalid input");

  const { inst: _inst, continue: _continue, input: _input, ...rest } = iss as any;
  rest.path ??= [];
  rest.message = message;
  if (ctx?.reportInput) {
    rest.input = _input;
  }
  return rest;
}

import { useReducer } from 'react';

type UseToggleAction<T> = (value?: React.SetStateAction<T>) => void;
export type UseToggleReturnValue<T> = [T, UseToggleAction<T>];

export function useToggle<T = boolean>(
  options: readonly T[] = [false, true] as any
): UseToggleReturnValue<T> {
  const [[option], toggle] = useReducer((state: T[], action: React.SetStateAction<T>) => {
    const value = action instanceof Function ? action(state[0]) : action;
    const index = Math.abs(state.indexOf(value));

    return state.slice(index).concat(state.slice(0, index));
  }, options as T[]);

  return [option, toggle as UseToggleAction<T>];
}

export namespace useToggle {
  export type ReturnValue<T> = UseToggleReturnValue<T>;
}

import { useRef } from 'react';
import { useForceUpdate } from '../use-force-update/use-force-update';

export function useMap<T, V>(initialState?: [T, V][]): Map<T, V> {
  const mapRef = useRef(new Map<T, V>(initialState));
  const forceUpdate = useForceUpdate();

  mapRef.current.set = (...args) => {
    Map.prototype.set.apply(mapRef.current, args);
    forceUpdate();
    return mapRef.current;
  };

  mapRef.current.clear = (...args) => {
    Map.prototype.clear.apply(mapRef.current, args);
    forceUpdate();
  };

  mapRef.current.delete = (...args) => {
    const res = Map.prototype.delete.apply(mapRef.current, args);
    forceUpdate();

    return res;
  };

  return mapRef.current;
}

import { useCallback, useState } from 'react';

export type UseSetStateCallback<T> = (
  state: Partial<T> | ((currentState: T) => Partial<T>)
) => void;

export type UseSetStateReturnValue<T> = [T, UseSetStateCallback<T>];

export function useSetState<T extends Record<string, any>>(
  initialState: T
): UseSetStateReturnValue<T> {
  const [state, setState] = useState(initialState);

  const _setState: UseSetStateCallback<T> = useCallback(
    (statePartial) =>
      setState((current) => ({
        ...current,
        ...(typeof statePartial === 'function' ? statePartial(current) : statePartial),
      })),
    []
  );

  return [state, _setState];
}

export namespace useSetState {
  export type Callback<T> = UseSetStateCallback<T>;
  export type ReturnValue<T> = UseSetStateReturnValue<T>;
}

export async function raceAgainstDeadline<T>(cb: () => Promise<T>, deadline: number): Promise<{ result: T, timedOut: false } | { timedOut: true }> {
  let timer: NodeJS.Timeout | undefined;
  // Note: not including "await" here truncates the async stack inside cb(), so always include it.
  return await Promise.race([
    cb().then(result => {
      return { result, timedOut: false };
    }),
    new Promise<{ timedOut: true }>(resolve => {
      if (!deadline)
        return;
      timer = setTimeout(() => resolve({ timedOut: true }), deadline - monotonicTime());
    }),
  ]).finally(() => {
    clearTimeout(timer);
  });
}

getOrCompute(key: K, compute: () => { value: V, size: number }): V {
  if (this._map.has(key)) {
    const result = this._map.get(key)!;
    // reinserting makes this the least recently used entry
    this._map.delete(key);
    this._map.set(key, result);
    return result.value;
  }

  const result = compute();

  while (this._map.size && this._size + result.size > this._maxSize) {
    const [firstKey, firstValue] = this._map.entries().next().value!;
    this._size -= firstValue.size;
    this._map.delete(firstKey);
  }

  this._map.set(key, result);
  this._size += result.size;
  return result.value;
}

export function compressCallLog(log: string[]): string[] {
  const lines: string[] = [];

  for (const block of findRepeatedSubsequences(log)) {
    for (let i = 0; i < block.sequence.length; i++) {
      const line = block.sequence[i];
      const leadingWhitespace = line.match(/^\s*/);
      const whitespacePrefix = '  ' + leadingWhitespace?.[0] || '';
      const countPrefix = `${block.count} × `;
      if (block.count > 1 && i === 0)
        lines.push(whitespacePrefix + countPrefix + line.trim());
      else if (block.count > 1)
        lines.push(whitespacePrefix + ' '.repeat(countPrefix.length - 2) + '- ' + line.trim());
      else
        lines.push(whitespacePrefix + '- ' + line.trim());
    }
  }
  return lines;
}

export function padImageToSize(image: ImageData, size: { width: number, height: number }): ImageData {
  if (image.width === size.width && image.height === size.height)
    return image;
  const buffer = new Uint8Array(size.width * size.height * 4);
  for (let y = 0; y < size.height; y++) {
    for (let x = 0; x < size.width; x++) {
      const to = (y * size.width + x) * 4;
      if (y < image.height && x < image.width) {
        const from = (y * image.width + x) * 4;
        buffer[to] = image.data[from];
        buffer[to + 1] = image.data[from + 1];
        buffer[to + 2] = image.data[from + 2];
        buffer[to + 3] = image.data[from + 3];
      } else {
        buffer[to] = 0;
        buffer[to + 1] = 0;
        buffer[to + 2] = 0;
        buffer[to + 3] = 0;
      }
    }
  }
  return { data: Buffer.from(buffer), width: size.width, height: size.height };
}

export function filterLogLevels(parseableString = ''): LogLevel[] {
  const sanitizedString = parseableString.replaceAll(' ', '').toLowerCase();

  if (sanitizedString[0] === '>') {
    const orEqual = sanitizedString[1] === '=';

    const logLevelIndex = (LOG_LEVELS as string[]).indexOf(
      sanitizedString.substring(orEqual ? 2 : 1),
    );

    if (logLevelIndex === -1) {
      throw new Error(`parse error (unknown log level): ${sanitizedString}`);
    }

    return LOG_LEVELS.slice(orEqual ? logLevelIndex : logLevelIndex + 1);
  } else if (sanitizedString.includes(',')) {
    return sanitizedString.split(',').filter(isLogLevel);
  }

  return isLogLevel(sanitizedString) ? [sanitizedString] : LOG_LEVELS;
}

type ImmerImpl = <T>(
  storeInitializer: StateCreator<T, [], []>,
) => StateCreator<T, [], []>

const immerImpl: ImmerImpl = (initializer) => (set, get, store) => {
  type T = ReturnType<typeof initializer>

  store.setState = (updater, replace, ...args) => {
    const nextState = (
      typeof updater === 'function' ? produce(updater as any) : updater
    ) as ((s: T) => T) | T | Partial<T>

    return set(nextState, replace as any, ...args)
  }

  return initializer(store.setState, get, store)
}

export const immer = immerImpl as unknown as Immer

async function request(query: string, variables: any): Promise<any> {
  const url = 'https://error-reports.prisma.sh/'
  const body = JSON.stringify({
    query,
    variables,
  })

  return await fetch(url, {
    method: 'POST',
    agent: getProxyAgent(url),
    body,
    headers: {
      Accept: 'application/json',
      'Content-Type': 'application/json',
    },
  })
    .then((response) => {
      if (!response.ok) {
        throw new Error(`Error during request: ${response.status} ${response.statusText} - Query: ${query}`)
      }
      return response.json() as any
    })
    .then((responseAsJson) => {
      if (responseAsJson.errors) {
        throw new Error(JSON.stringify(responseAsJson.errors))
      }
      return responseAsJson.data
    })
}

export function hasMultipleVersions(versions: string[]) {
  return versions.find((v) => {
    const major = semver.major(v);
    // If major version === 0, treat minor or patch as major
    if (major === 0) {
      const minor = semver.minor(v);
      if (minor === 0) {
        const patch = semver.patch(v);
        return versions.some((v2) => {
          return semver.patch(v2) !== patch;
        });
      }

      return versions.some((v2) => {
        return semver.minor(v2) !== minor;
      });
    }

    return versions.some((v2) => {
      return semver.major(v2) !== major;
    });
  });
}

function parseErrorCode({
  code,
  category,
}: Pick<StorybookError, 'code' | 'category'>): `SB_${typeof category}_${string}` {
  const paddedCode = String(code).padStart(4, '0');
  return `SB_${category}_${paddedCode}`;
}

export function appendErrorRef(url: string): string {
  // Skip if not storybook.js.org OR already has ref=error
  if (/^(?!.*storybook\.js\.org)|[?&]ref=error\b/.test(url)) {
    return url;
  }

  try {
    const urlObj = new URL(url);
    urlObj.searchParams.set('ref', 'error');
    return urlObj.toString();
  } catch {
    // Fallback for invalid URLs - return as-is
    return url;
  }
}

export function map<TValueBefore, TError, TValueAfter>(
  project: (value: TValueBefore, index: number) => TValueAfter,
): OperatorFunction<TValueBefore, TError, TValueAfter, TError> {
  return (source) => {
    return observable((destination) => {
      let index = 0;
      const subscription = source.subscribe({
        next(value) {
          destination.next(project(value, index++));
        },
        error(error) {
          destination.error(error);
        },
        complete() {
          destination.complete();
        },
      });
      return subscription;
    });
  };
}

export function tap<TValue, TError>(
  observer: Partial<Observer<TValue, TError>>,
): MonoTypeOperatorFunction<TValue, TError> {
  return (source) => {
    return observable((destination) => {
      return source.subscribe({
        next(value) {
          observer.next?.(value);
          destination.next(value);
        },
        error(error) {
          observer.error?.(error);
          destination.error(error);
        },
        complete() {
          observer.complete?.();
          destination.complete();
        },
      });
    });
  };
}

export function timerResource(ms: number) {
  let timer: ReturnType<typeof setTimeout> | null = null;

  return makeResource(
    {
      start() {
        if (timer) {
          throw new Error('Timer already started');
        }

        const promise = new Promise<typeof disposablePromiseTimerResult>(
          (resolve) => {
            timer = setTimeout(() => resolve(disposablePromiseTimerResult), ms);
          },
        );
        return promise;
      },
    },
    () => {
      if (timer) {
        clearTimeout(timer);
      }
    },
  );
}

export const areUint8ArraysEqual = (
    left: Uint8Array,
    right: Uint8Array,
): boolean => {
    if (left === right) {
        return true
    }

    if (isBuffer(left) && isBuffer(right)) {
        return left.equals(right)
    }

    if (left.byteLength !== right.byteLength) {
        return false
    }

    for (let index = 0; index < left.byteLength; index++) {
        if (left[index] !== right[index]) {
            return false
        }
    }

    return true
}

