export function printServerUrls(
  urls: ResolvedServerUrls,
  optionsHost: string | boolean | undefined,
  info: Logger['info'],
): void {
  const colorUrl = (url: string) =>
    colors.cyan(url.replace(/:(\d+)\//, (_, port) => `:${colors.bold(port)}/`))
  for (const url of urls.local) {
    info(`  ${colors.green('➜')}  ${colors.bold('Local')}:   ${colorUrl(url)}`)
  }
  for (const url of urls.network) {
    info(`  ${colors.green('➜')}  ${colors.bold('Network')}: ${colorUrl(url)}`)
  }
  if (urls.network.length === 0 && optionsHost === undefined) {
    info(
      colors.dim(`  ${colors.green('➜')}  ${colors.bold('Network')}: use `) +
        colors.bold('--host') +
        colors.dim(' to expose'),
    )
  }
}

export function resolveChokidarOptions(
  options: WatchOptions | undefined,
  resolvedOutDirs: Set<string>,
  emptyOutDir: boolean,
  cacheDir: string,
): WatchOptions {
  const { ignored: ignoredList, ...otherOptions } = options ?? {}
  const ignored: WatchOptions['ignored'] = [
    '**/.git/**',
    '**/node_modules/**',
    '**/test-results/**', // Playwright
    escapePath(cacheDir) + '/**',
    ...arraify(ignoredList || []),
  ]
  if (emptyOutDir) {
    ignored.push(
      ...[...resolvedOutDirs].map((outDir) => escapePath(outDir) + '/**'),
    )
  }

  const resolvedWatchOptions: WatchOptions = {
    ignored,
    ignoreInitial: true,
    ignorePermissionErrors: true,
    ...otherOptions,
  }

  return resolvedWatchOptions
}

private addDefaultInternetRoute(subnet: ISubnetV2, igw: InternetGateway, options?: InternetGatewayOptions): void {
  // Add default route to IGW for IPv6
  if (subnet.ipv6CidrBlock) {
    new Route(this, `${subnet.node.id}-DefaultIPv6Route`, {
      routeTable: subnet.routeTable,
      destination: options?.ipv6Destination ?? '::/0',
      target: { gateway: igw },
      routeName: 'CDKDefaultIPv6Route',
    });
  }
  // Add default route to IGW for IPv4
  new Route(this, `${subnet.node.id}-DefaultRoute`, {
    routeTable: subnet.routeTable,
    destination: options?.ipv4Destination ?? '0.0.0.0/0',
    target: { gateway: igw },
    routeName: 'CDKDefaultIPv4Route',
  });
}

constructor(scope: Construct, id: string) {
  super(scope, id);

  Object.defineProperty(this, CFN_ELEMENT_SYMBOL, { value: true });

  this.stack = Stack.of(this);

  // eslint-disable-next-line no-restricted-syntax
  this.logicalId = Lazy.uncachedString({ produce: () => this._synthesizeLogicalId() }, {
    displayHint: `${notTooLong(Node.of(this).path)}.LogicalID`,
  });

  if (!this.node.tryGetContext(cxapi.DISABLE_LOGICAL_ID_METADATA)) {
