  }
}

private specialCaseRefs(value: any): any {
  if (value in this.parameters) {
    return this.parameters[value];
  }
  switch (value) {
    case 'AWS::AccountId': return Aws.ACCOUNT_ID;
    case 'AWS::Region': return Aws.REGION;
    case 'AWS::Partition': return Aws.PARTITION;
    case 'AWS::URLSuffix': return Aws.URL_SUFFIX;
    case 'AWS::NotificationARNs': return Aws.NOTIFICATION_ARNS;
    case 'AWS::StackId': return Aws.STACK_ID;
    case 'AWS::StackName': return Aws.STACK_NAME;
    // AWS.NO_VALUE is defined as a string, however NoValue should be able to use any type
    case 'AWS::NoValue': return Token.asAny(Aws.NO_VALUE);
    default: return undefined;
  }
}

export async function infoAllow404(packageJson: PackageJSON) {
  let pkgInfo = await getPackageInfo(packageJson);
  if (pkgInfo.error?.code === "E404") {
    warn(`Received 404 for npm info ${pc.cyan(`"${packageJson.name}"`)}`);
    return { published: false, pkgInfo: {} };
  }
  if (pkgInfo.error) {
    error(
      `Received an unknown error code: ${
        pkgInfo.error.code
      } for npm info ${pc.cyan(`"${packageJson.name}"`)}`
    );
    error(pkgInfo.error.summary);
    if (pkgInfo.error.detail) error(pkgInfo.error.detail);

    throw new ExitError(1);
  }
  return { published: true, pkgInfo };
}

export async function execWithOutput(
  command: string,
  args: string[],
  options: { ignoreReturnCode?: boolean; cwd: string }
) {
  process.stdout.write(`Running: ${command} ${args.join(" ")}` + os.EOL);
  let childProcess = spawn(command, args, {
    cwd: options.cwd,
  });
  childProcess.on("stdout", (data) => process.stdout.write(data));
  childProcess.on("stderr", (data) => process.stderr.write(data));
  let result = await childProcess;
  if (!options?.ignoreReturnCode && result.code !== 0) {
    throw new Error(
      `The command "${command} ${args.join(" ")}" failed with code ${
        result.code
      }\n${result.stdout.toString("utf8")}\n${result.stderr.toString("utf8")}`
    );
  }
  return {
    code: result.code,
    stdout: result.stdout.toString("utf8"),
    stderr: result.stderr.toString("utf8"),
  };
}

export function formatNumber(val: number): string {
  if (val >= 1e12) {
    return `${toFixed(val / 1e12)}T`;
  }
  if (val >= 1e9) {
    return `${toFixed(val / 1e9)}B`;
  }
  if (val >= 1e6) {
    return `${toFixed(val / 1e6)}M`;
  }
  if (val >= 1e3) {
    return `${toFixed(val / 1e3)}k`;
  }
  if (val >= 1) {
    return val.toString();
  }
  if (val >= 1e-3) {
    return `${toFixed(val * 1e3)}m`;
  }
  if (val >= 1e-6) {
    return `${toFixed(val * 1e6)}µ`;
  }
  if (val >= 1e-9) {
    return `${toFixed(val * 1e9)}n`;
  }
  if (val >= 1e-12) {
    return `${toFixed(val * 1e12)}p`;
  }
  return val.toString();
}

export function initializeContext(params: JSONSchemaGeneratorParams): ToJSONSchemaContext {
  // Normalize target: convert old non-hyphenated versions to hyphenated versions
  let target: ToJSONSchemaContext["target"] = params?.target ?? "draft-2020-12";
  if (target === "draft-4") target = "draft-04";
  if (target === "draft-7") target = "draft-07";

  return {
    processors: params.processors ?? {},
    metadataRegistry: params?.metadata ?? globalRegistry,
    target,
    unrepresentable: params?.unrepresentable ?? "throw",
    override: (params?.override as any) ?? (() => {}),
    io: params?.io ?? "output",
    counter: 0,
    seen: new Map(),
    cycles: params?.cycles ?? "ref",
    reused: params?.reused ?? "inline",
    external: params?.external ?? undefined,
  };
}

emitLog(m: { prefix: string; level: string | number; message?: string }): void {
  if (this._paused) {
    this._buffer.push(m);
    return;
  }
  if (this.progressEnabled) {
    this.gauge.pulse(m.prefix);
  }
  const l = this.levels[m.level];
  if (l === undefined || l < this.levels[this.level] || (l > 0 && !isFinite(l))) {
    return;
  }
  const disp = this.disp[m.level];
  this.clearProgress();
  m.message?.split(/\r?\n/).forEach((line) => {
    const heading = this.heading;
    if (heading) {
      this.write(heading, this.headingStyle);
      this.write(" ");
    }
    this.write(disp, this.style[m.level]);
    const p = m.prefix || "";
    if (p) {
      this.write(" ");
    }
    this.write(p, this.prefixStyle);
    this.write(" " + line + "\n");
  });
  this.showProgress();
}

public createExceptionLayerProxy(
  targetCallback: <TError, TRequest, TResponse>(
    err: TError,
    req: TRequest,
    res: TResponse,
    next: () => void,
  ) => void | Promise<void>,
  exceptionsHandler: ExceptionsHandler,
) {
  return async <TError, TRequest, TResponse>(
    err: TError,
    req: TRequest,
    res: TResponse,
    next: () => void,
  ) => {
    try {
      await targetCallback(err, req, res, next);
    } catch (e) {
      const host = new ExecutionContextHost([req, res, next]);
      exceptionsHandler.next(e, host);
      return res;
    }
  };
}

export const getApplicationFilesCountUncached = async (basePath: string) => {
  const bothCasesNameMatches = nameMatches.flatMap((match) => [
    match,
    [match[0].toUpperCase(), ...match.slice(1)].join(''),
  ]);

  const globs = bothCasesNameMatches.flatMap((match) =>
    extensions.map((extension) => `${basePath}${sep}*${match}*.${extension}`)
  );

  try {
    return await execCommandCountLines('git', ['ls-files', '--', ...globs]);
  } catch {
    return undefined;
  }
};

