export async function getProcedureAtPath(
  router: Pick<Router<any, any>, '_def'>,
  path: string,
): Promise<AnyProcedure | null> {
  const { _def } = router;
  let procedure = _def.procedures[path];

  while (!procedure) {
    const key = Object.keys(_def.lazy).find((key) => path.startsWith(key));
    // console.log(`found lazy: ${key ?? 'NOPE'} (fullPath: ${fullPath})`);

    if (!key) {
      return null;
    }
    // console.log('loading', key, '.......');
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    const lazyRouter = _def.lazy[key]!;
    await lazyRouter.load();

    procedure = _def.procedures[path];
  }

  return procedure;
}

_truncate(record: IterableChangeRecord_<V> | null) {
  // Anything after that needs to be removed;
  while (record !== null) {
    const nextRecord: IterableChangeRecord_<V> | null = record._next;
    this._addToRemovals(this._unlink(record));
    record = nextRecord;
  }
  if (this._unlinkedRecords !== null) {
    this._unlinkedRecords.clear();
  }

  if (this._additionsTail !== null) {
    this._additionsTail._nextAdded = null;
  }
  if (this._movesTail !== null) {
    this._movesTail._nextMoved = null;
  }
  if (this._itTail !== null) {
    this._itTail._next = null;
  }
  if (this._removalsTail !== null) {
    this._removalsTail._nextRemoved = null;
  }
  if (this._identityChangesTail !== null) {
    this._identityChangesTail._nextIdentityChange = null;
  }
}

_addAfter(
  record: IterableChangeRecord_<V>,
  prevRecord: IterableChangeRecord_<V> | null,
  index: number,
): IterableChangeRecord_<V> {
  this._insertAfter(record, prevRecord, index);

  if (this._additionsTail === null) {
    // TODO(vicb):
    // assert(this._additionsHead === null);
    this._additionsTail = this._additionsHead = record;
  } else {
    // TODO(vicb):
    // assert(_additionsTail._nextAdded === null);
    // assert(record._nextAdded === null);
    this._additionsTail = this._additionsTail._nextAdded = record;
  }
  return record;
}

private get bgNeutral() {
  // Low chroma, but not 0, if possible, to produce harmony with accents in the UI
  const color = this.bgAccent.clone();

  if (this.seedIsAchromatic) {
    color.oklch.c = 0;
  }

  if (this.seedIsCold && !this.seedIsAchromatic) {
    color.oklch.c = 0.02;
  }

  if (!this.seedIsCold && !this.seedIsAchromatic) {
    color.oklch.c = 0.01;
  }

  if (color.oklch.l > 0.8) {
    color.oklch.l -= 0.32;
  }

  if (color.oklch.l > 0.6 && color.oklch.l <= 0.8) {
    color.oklch.l -= 0.27;
  }

  if (color.oklch.l > 0.45 && color.oklch.l <= 0.6) {
    color.oklch.l -= 0.2;
  }

  return color;
}

export const cssRule = (tokens: Theme) => {
  let styles = "";

  objectKeys(tokens).forEach((tokenKey) => {
    const token = tokens[tokenKey];

    if (token == null) return;

    if (isObject(token)) {
      if (tokenKey === "typography") {
        styles += objectKeys(token as NonNullable<Theme["typography"]>).reduce(
          (prev: string, key) => {
            return `${prev} --font-size-${key}: ${(token[key] as TypographyVariantMetric).fontSize};`;
          },
          "",
        );

        return;
      }

      objectKeys(token).forEach((key) => {
        //@ts-expect-error: type mismatch
        styles += `--${kebabCase(token[key].type)}-${kebabCase(key)}: ${
          //@ts-expect-error: type mismatch
          token[key].value
        };`;
      });
    }
  });

  return styles;
};

export const migrateDatePickerMinMaxDate = (currentDSL: DSLWidget) => {
  if (currentDSL.type === "DATE_PICKER_WIDGET2" && currentDSL.version === 2) {
    if (currentDSL.minDate === "2001-01-01 00:00") {
      currentDSL.minDate = "1920-12-31T18:30:00.000Z";
    }

    if (currentDSL.maxDate === "2041-12-31 23:59") {
      currentDSL.maxDate = "2121-12-31T18:29:00.000Z";
    }
  }

  if (currentDSL.children && currentDSL.children.length) {
    currentDSL.children.map((eachWidgetDSL: DSLWidget) => {
      migrateDatePickerMinMaxDate(eachWidgetDSL);
    });
  }

  return currentDSL;
};

export const handle413Error = async (error: AxiosError) => {
  if (error?.response?.status === 413) {
    return Promise.reject({
      ...error,
      clientDefinedError: true,
      statusCode: "AE-APP-4013",
      message: createMessage(ERROR_413, 100),
      pluginErrorDetails: {
        appsmithErrorCode: "AE-APP-4013",
        appsmithErrorMessage: createMessage(ERROR_413, 100),
        errorType: "INTERNAL_ERROR", // this value is from the server, hence cannot construct enum type.
        title: createMessage(GENERIC_API_EXECUTION_ERROR),
      },
    });
  }

  return null;
};

export const SESSION_TIMEOUT = 1000 * 60 * 60 * 2; // 2h

interface Session {
  id: string;
  lastUsed: number;
}

let sessionId: string | undefined;

export const resetSessionIdForTest = (val: string | undefined = undefined) => {
  sessionId = val;
};

export const getSessionId = async () => {
  const now = Date.now();
  if (!sessionId) {
    const session: Session | undefined = await cache.get('session');
    if (session && session.lastUsed >= now - SESSION_TIMEOUT) {
      sessionId = session.id;
    } else {
      sessionId = nanoid();
    }
  }
  await cache.set('session', { id: sessionId, lastUsed: now });
  return sessionId;
};

