      'amazon-linux-2/' : 'amazon-linux-2-arm64/' : '')
    + (this.nodeType === NodeType.GPU ? 'amazon-linux-2-gpu/' : '')
    + (this.nodeType === NodeType.INFERENTIA ? 'amazon-linux-2-gpu/' : '')
    + (this.nodeType === NodeType.TRAINIUM ? 'amazon-linux-2-gpu/' : '')
